const int mod = 1e9 + 7;
const int maxn = 1e6 + 5;
int dp[maxn][maxn];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        int ans = 0;
        for (int i = 1; i <= R / i; i++) {
            int cnt = 0;
            for (int j = 0; j <= R / i; j++) {
                if (dp[i][j]) {
                    cnt++;
                }
            }
            ans = (ans + cnt * (R / i - j + 1)) % mod;
        }
        printf("%d\n", ans);
    }
    return 0;
}

